output-contract.example:
{
  "slug": "langchain-memory",
  "version": "2.0.0",
  "decision": {
    "memory_type": "buffer",
    "store_backend": "redis",
    "session_id_strategy": "uuid",
    "ttl_seconds": 3600
  },
  "drivers": {"expected_turns": 6, "recall_pattern": "recency", "entity_focus": false},
  "rejected": [
    {"memory_type": "summary", "reason": "Under 10 turns; summary cost > buffer cost."},
    {"memory_type": "vector", "reason": "No semantic recall pattern; cross-session leakage risk without filter."}
  ],
  "wiring": {
    "snippet": "RunnableWithMessageHistory(chain, get_session_history, input_messages_key='input', history_messages_key='history')",
    "history_messages_key": "history",
    "input_messages_key": "input"
  },
  "audit": {"rule_refs": ["r1", "r13", "r14"]}
}
